local resty = require "resty"
local http = resty.http.new()

function proxy(ngx)
  local url = ngx.var.arg_url
  if not url then
    ngx.log(ngx.ERR, "Missing URL argument")
    return ngx.exit(400)
  end

  -- Fetch content using lua-resty-http
  local res, err = http:request_uri(url)
  if not res then
    ngx.log(ngx.ERR, "Failed to fetch content from URL: ", url)
    return ngx.exit(500)
  end

  -- Return fetched content as response body
  ngx.say(res.body)
end